1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Damage[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Scenario = { customer: Customer; steps: Step[] };
9	
10	const DEDUCTIBLE = 100;
11	
12	const MAIN_ITEM_INSURANCE_VALUE: Record<string, number> = {
13	  sword: 1000,
14	  amulet: 600,
15	};
16	
17	const PROCESSING_FEE = 5;
18	const FIRST_INSURANCE_SURCHARGE = 0.1;
19	const CURSE_SURCHARGE = 0.5;
20	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
21	const HIGH_ENCHANTMENT_THRESHOLD = 5;
22	const LOYALTY_DISCOUNT = 0.2;
23	const LOYALTY_YEARS_THRESHOLD = 2;
24	const FOLLOWUP_DISCOUNT = 0.15;
25	const COMPONENT_BASE_PREMIUM = 25;
26	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
27	const COMPONENT_BLOCK_SIZE = 3;
28	
29	const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
30	  sword: 100,
31	  amulet: 60,
32	};
33	
34	const isMainItem = (item: Item): boolean => item.type in MAIN_ITEM_BASE_PREMIUM;
35	
36	const ceilWithEpsilon = (n: number): number => Math.ceil(Math.round(n * 1e8) / 1e8);
37	
38	const rateAmount = (base: number, applies: boolean, rate: number): number =>
39	  applies ? base * rate : 0;
40	
41	const isHighlyEnchanted = (item: Item): boolean =>
42	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
43	
44	const mainItemBase = (item: Item): number => MAIN_ITEM_BASE_PREMIUM[item.type];
45	
46	const mainItemSurcharges = (item: Item): number => {
47	  const base = mainItemBase(item);
48	  return (
49	    rateAmount(base, item.cursed === true, CURSE_SURCHARGE) +
50	    rateAmount(base, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE)
51	  );
52	};
53	
54	const componentGroupBase = (count: number): number => {
55	  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
56	  const leftover = count % COMPONENT_BLOCK_SIZE;
57	  return blocks * COMPONENT_BLOCK_BASE_PREMIUM + leftover * COMPONENT_BASE_PREMIUM;
58	};
59	
60	const componentCountsByType = (components: Item[]): Map<string, number> => {
61	  const counts = new Map<string, number>();
62	  for (const item of components) {
63	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
64	  }
65	  return counts;
66	};
67	
68	const sumComponentGroupBases = (components: Item[]): number =>
69	  [...componentCountsByType(components).values()].reduce(
70	    (total, count) => total + componentGroupBase(count),
71	    0,
72	  );
73	
74	const partitionItems = (items: Item[]): { mainItems: Item[]; components: Item[] } => {
75	  const mainItems: Item[] = [];
76	  const components: Item[] = [];
77	  for (const item of items) {
78	    (isMainItem(item) ? mainItems : components).push(item);
79	  }
80	  return { mainItems, components };
81	};
82	
83	const sumMainItemBases = (mainItems: Item[]): number =>
84	  mainItems.reduce((sum, item) => sum + mainItemBase(item), 0);
85	
86	const sumMainItemSurcharges = (mainItems: Item[]): number =>
87	  mainItems.reduce((sum, item) => sum + mainItemSurcharges(item), 0);
88	
89	const isLoyalCustomer = (customer: Customer): boolean =>
90	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
91	
92	const totalDiscount = (policyBase: number, customer: Customer, isFollowUp: boolean): number =>
93	  rateAmount(policyBase, isLoyalCustomer(customer), LOYALTY_DISCOUNT) +
94	  rateAmount(policyBase, isFollowUp, FOLLOWUP_DISCOUNT);
95	
96	const priceQuote = (step: QuoteStep, customer: Customer, isFollowUp: boolean): { premium: number } => {
97	  const { mainItems, components } = partitionItems(step.items);
98	  const policyBase = sumMainItemBases(mainItems) + sumComponentGroupBases(components);
99	  const surcharges = sumMainItemSurcharges(mainItems);
100	  const firstInsurance = policyBase * FIRST_INSURANCE_SURCHARGE;
101	  const discounts = totalDiscount(policyBase, customer, isFollowUp);
102	  return {
103	    premium: ceilWithEpsilon(policyBase + surcharges + firstInsurance - discounts + PROCESSING_FEE),
104	  };
105	};
106	
107	const countQuotesBefore = (steps: Step[], index: number): number =>
108	  steps.slice(0, index).filter((s) => s.op === "quote").length;
109	
110	const insuranceSumOf = (step: QuoteStep): number =>
111	  step.items.reduce((sum, item) => sum + (MAIN_ITEM_INSURANCE_VALUE[item.type] ?? 0), 0);
112	
113	const processClaim = (step: ClaimStep, steps: Step[]): { payout: number; remainingCap: number } => {
114	  const policyStep = steps[step.policy] as QuoteStep;
115	  const cap = 2 * insuranceSumOf(policyStep);
116	  const payout = step.incident.damages.reduce(
117	    (sum, d) => sum + Math.max(0, d.amount - DEDUCTIBLE),
118	    0,
119	  );
120	  return { payout, remainingCap: cap - payout };
121	};
122	
123	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
124	  results: scenario.steps.map((step, i) =>
125	    step.op === "quote"
126	      ? priceQuote(step, scenario.customer, countQuotesBefore(scenario.steps, i) > 0)
127	      : processClaim(step, scenario.steps),
128	  ),
129	});
