const insuranceSumOf = (step: QuoteStep): number =>
  step.items.reduce((sum, item) => sum + (MAIN_ITEM_INSURANCE_VALUE[item.type] ?? 0), 0);

const damagePayout = (damage: Damage): number =>
  Math.max(0, damage.amount - DEDUCTIBLE);

const totalPayout = (damages: Damage[]): number =>
  damages.reduce((sum, d) => sum + damagePayout(d), 0);

const processClaim = (step: ClaimStep, steps: Step[]): { payout: number; remainingCap: number } => {
  const policyStep = steps[step.policy] as QuoteStep;
  const cap = CAP_MULTIPLIER * insuranceSumOf(policyStep);
  const payout = totalPayout(step.incident.damages);
  return { payout, remainingCap: cap - payout };
};
